// src/context/AppContext.js
import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { initialTimetable, DAYS, PERIOD_TIMES } from '../data/initialData';

const AppContext = createContext();
const API = 'http://localhost:5000/api';

const authHeaders = () => ({
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${localStorage.getItem('token')}`,
});

export function AppProvider({ children }) {
  const [staff, setStaff] = useState([]);
  const [timetable, setTimetable] = useState(initialTimetable);
  const [leaveRequests, setLeaveRequests] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [currentUser, setCurrentUser] = useState(null);

  // ✅ Staff fetch karo
  const fetchStaff = useCallback(async () => {
    try {
      const res = await fetch(`${API}/staff`, { headers: authHeaders() });
      const data = await res.json();
      if (Array.isArray(data)) setStaff(data);
    } catch (err) {
      console.error('Staff fetch error:', err);
    }
  }, []);

  // ✅ Leave requests fetch karo
  const fetchLeaves = useCallback(async () => {
    try {
      const res = await fetch(`${API}/leaves`, { headers: authHeaders() });
      const data = await res.json();
      if (Array.isArray(data)) setLeaveRequests(data);
    } catch (err) {
      console.error('Leaves fetch error:', err);
    }
  }, []);

  // ✅ Notifications fetch karo
  const fetchNotifications = useCallback(async () => {
    try {
      const res = await fetch(`${API}/notifications`, { headers: authHeaders() });
      const data = await res.json();
      if (Array.isArray(data)) setNotifications(data);
    } catch (err) {
      console.error('Notifications fetch error:', err);
    }
  }, []);

  // Login hone par data fetch karo
  useEffect(() => {
    if (currentUser && currentUser.token) {
      fetchStaff();
      fetchLeaves();
      fetchNotifications();
    }
  }, [currentUser]);

  const findFreeTeachers = useCallback((day, period, excludeTeacherId) => {
    const busyTeacherIds = new Set();
    Object.entries(timetable).forEach(([teacherId, slots]) => {
      if (parseInt(teacherId) === excludeTeacherId) return;
      slots.forEach(slot => {
        if (slot.day === day && slot.period === period) {
          busyTeacherIds.add(parseInt(teacherId));
        }
      });
    });
    return staff.filter(t => {
      const id = t._id || t.id;
      return id !== excludeTeacherId && !busyTeacherIds.has(parseInt(id));
    });
  }, [timetable, staff]);

  const getTeacherSlots = useCallback((teacherId, fromDate, toDate) => {
    const slots = timetable[teacherId] || [];
    const affectedSlots = [];
    const start = new Date(fromDate);
    const end = new Date(toDate);
    for (let d = new Date(start); d <= end; d.setDate(d.getDate() + 1)) {
      const dayName = DAYS[d.getDay() - 1];
      if (!dayName) continue;
      const dateStr = d.toISOString().split('T')[0];
      slots.forEach(slot => {
        if (slot.day === dayName) {
          const freeTeachers = findFreeTeachers(dayName, slot.period, teacherId);
          affectedSlots.push({
            date: dateStr,
            day: dayName,
            period: slot.period,
            class: slot.class,
            time: PERIOD_TIMES[slot.period],
            freeTeachers,
          });
        }
      });
    }
    return affectedSlots;
  }, [timetable, findFreeTeachers]);

  // ✅ Leave apply — API call
  const applyLeave = useCallback(async (teacherId, fromDate, toDate, reason, extraData = {}) => {
    try {
      const res = await fetch(`${API}/leaves`, {
        method: 'POST',
        headers: authHeaders(),
        body: JSON.stringify({
          ...extraData,
          fromDate,
          toDate,
          reason,
          substituteRequests: getTeacherSlots(teacherId, fromDate, toDate).map((slot, index) => ({
            ...slot,
            assignedTeacherId: null,
            subStatus: 'pending',
          })),
        }),
      });
      const data = await res.json();
      await fetchLeaves();
      return data;
    } catch (err) {
      console.error('Apply leave error:', err);
    }
  }, [getTeacherSlots, fetchLeaves]);

  // ✅ Leave status update — API call
  const updateLeaveStatus = useCallback(async (requestId, status) => {
    try {
      await fetch(`${API}/leaves/${requestId}/status`, {
        method: 'PUT',
        headers: authHeaders(),
        body: JSON.stringify({ status }),
      });
      await fetchLeaves();
      await fetchStaff(); // Balance update ke liye
      await fetchNotifications();
    } catch (err) {
      console.error('Update status error:', err);
    }
  }, [fetchLeaves, fetchStaff, fetchNotifications]);

  // ✅ Accept substitute — API call
  const acceptSubstitute = useCallback(async (requestId, slotIndex, teacherId) => {
    try {
      await fetch(`${API}/leaves/${requestId}/accept/${slotIndex}`, {
        method: 'PUT',
        headers: authHeaders(),
      });
      await fetchLeaves();
      await fetchNotifications();
    } catch (err) {
      console.error('Accept substitute error:', err);
    }
  }, [fetchLeaves, fetchNotifications]);

  // ✅ Notification read mark
  const markNotificationRead = useCallback(async (id) => {
    try {
      await fetch(`${API}/notifications/${id}`, {
        method: 'PUT',
        headers: authHeaders(),
      });
      await fetchNotifications();
    } catch (err) {
      // Local update fallback
      setNotifications(prev => prev.map(n => n._id === id ? { ...n, read: true } : n));
    }
  }, [fetchNotifications]);

  const addTimetableEntry = useCallback((teacherId, entry) => {
    setTimetable(prev => ({
      ...prev,
      [teacherId]: [...(prev[teacherId] || []), entry],
    }));
  }, []);

  const removeTimetableEntry = useCallback((teacherId, index) => {
    setTimetable(prev => ({
      ...prev,
      [teacherId]: prev[teacherId].filter((_, i) => i !== index),
    }));
  }, []);

  const addStaffMember = useCallback(async (member) => {
    try {
      const res = await fetch(`${API}/staff`, {
        method: 'POST',
        headers: authHeaders(),
        body: JSON.stringify({ ...member, password: 'staff123' }),
      });
      const data = await res.json();
      await fetchStaff();
      return data;
    } catch (err) {
      console.error('Add staff error:', err);
    }
  }, [fetchStaff]);

  return (
    <AppContext.Provider value={{
      staff, setStaff,
      timetable, setTimetable,
      leaveRequests, setLeaveRequests,
      notifications, markNotificationRead,
      currentUser, setCurrentUser,
      applyLeave,
      updateLeaveStatus,
      updateSubstitute: () => {},
      acceptSubstitute,
      addTimetableEntry,
      removeTimetableEntry,
      addStaffMember,
      getTeacherSlots,
      findFreeTeachers,
      fetchLeaves,
      fetchStaff,
      fetchNotifications,
    }}>
      {children}
    </AppContext.Provider>
  );
}

export const useApp = () => useContext(AppContext);
